import React from 'react';
import lg, { LangStringKey } from '../config/lang';
import type { Lang } from '../customHooks/toggleScroll';

interface TextTitleProps extends Omit<React.HTMLAttributes<HTMLSpanElement>, 'children'> {
  children: LangStringKey;
  lang?: Lang;
  color?: string;
  italic?: boolean;
  bold?: boolean;
  spacing?: number | string;
}

const TextTitle = ({
  children,
  lang = 'fr',
  color = 'black',
  italic = false,
  bold = false,
  spacing = 'normal',
  ...rest
}: TextTitleProps) => {
  return (
    <span
      className="text-[34px] max-[750px]:text-[26px]"
      style={{
        color,
        fontWeight: bold ? 'bold' : 'normal',
        fontStyle: italic ? 'italic' : 'normal',
        letterSpacing:
          typeof spacing === 'number' ? `${spacing}px` : spacing,
      }}
      {...rest}
    >
      {lg[lang][children]}
    </span>
  );
};

export default TextTitle;
